// ---------------------------------------------------------------------------
// Instruction Types (match backend OperationType enum)
// ---------------------------------------------------------------------------

/**
 * Operation types — from UAC OperationType enum (ui-reference-data.json → uac_enums.OperationType).
 * These are the DeFi-relevant subset. Full list includes BUY/SELL for CeFi.
 */
export const OPERATION_TYPES = [
  // From UAC OperationType enum
  "SWAP",
  "LEND",
  "BORROW",
  "REPAY",
  "WITHDRAW",
  "DEPOSIT",
  "REBALANCE",
  "ADD_LIQUIDITY",
  "REMOVE_LIQUIDITY",
  "COLLECT_FEES",
  // DeFi-specific extensions (in strategy-service, not yet in UAC enum)
  "TRANSFER",
  "TRADE",        // CeFi perp trade (maps to InstructionType.TRADE)
  "STAKE",
  "UNSTAKE",
  "FLASH_BORROW",
  "FLASH_REPAY",
] as const;

export type OperationType = (typeof OPERATION_TYPES)[number];

// Backward compat alias
export const INSTRUCTION_TYPES = OPERATION_TYPES;
export type InstructionType = OperationType;

