// ---------------------------------------------------------------------------
// Strategy Instruction (matches backend StrategyInstruction)
// ---------------------------------------------------------------------------

export interface StrategyInstruction {
  instruction_id: string;
  strategy_id: DeFiStrategyId;
  timestamp: string;
  operation: InstructionType;
  algo_type: AlgoType;
  instrument_id: string; // canonical: "AAVEV3-ETHEREUM:A_TOKEN:AUSDC@ETHEREUM"
  from_venue: string;
  to_venue: string;
  token_in: string;
  token_out?: string;
  amount: number;
  direction?: "LONG" | "SHORT";
  benchmark_price: number;
  max_slippage_bps: number;
  expected_output: number; // what strategy expects to receive
  is_atomic?: boolean;
  metadata?: Record<string, string>;
}

// ---------------------------------------------------------------------------
// Instant P&L (alpha decomposition per instruction)
// ---------------------------------------------------------------------------

export interface InstantPnL {
  /** Gross P&L before costs: actual_output - expected_output */
  gross_pnl: number;
  /** Price slippage vs benchmark */
  price_slippage_usd: number;
  /** Gas cost in USD */
  gas_cost_usd: number;
  /** Swap/trading fee */
  trading_fee_usd: number;
  /** Bridge fee (cross-chain only) */
  bridge_fee_usd: number;
  /** Net P&L after all costs */
  net_pnl: number;
  /** Was max_slippage_bps exceeded? */
  slippage_exceeded: boolean;
}

// ---------------------------------------------------------------------------
// Trade History (running totals)
// ---------------------------------------------------------------------------

export interface TradeHistoryRow {
  seq: number;
  timestamp: string;
  instruction_type: InstructionType;
  algo_type: AlgoType;
  instrument_id: string;
  venue: string;
  amount: number;
  price: number;
  expected_output: number;
  actual_output: number;
  instant_pnl: InstantPnL;
  running_pnl: number; // cumulative net P&L
  status: "pending" | "confirmed" | "filled" | "failed" | "reverted";
  tx_hash?: string;
}

// ---------------------------------------------------------------------------
// Risk Dimensions
// ---------------------------------------------------------------------------

export type RiskLevel = "low" | "medium" | "high" | "critical";

export interface StrategyRiskProfile {
  strategy_id: DeFiStrategyId;
  /** Smart contract / oracle / governance risk */
  protocol_risk: RiskLevel;
  /** Individual token price collapse exposure */
  coin_isolated_risk: RiskLevel;
  /** Spot vs perp price divergence (basis strategies) */
  basis_risk: RiskLevel;
  /** Funding rate going negative across venues */
  funding_rate_risk: RiskLevel;
  /** % drawdown to close ALL positions at once */
  liquidity_risk_pct: number;
  /** Qualitative description */
  risk_notes: string;
}

// ---------------------------------------------------------------------------
// Delta Neutrality
// ---------------------------------------------------------------------------

export interface DeltaExposure {
  strategy_id: DeFiStrategyId;
  /** What this strategy is supposed to be neutral to */
  neutral_to: string; // "USD" | "ETH" | "SOL" | "BTC"
  /** Current net delta per underlying */
  net_delta_usd: number;
  net_delta_eth: number;
  net_delta_sol: number;
  net_delta_btc: number;
  /** Deviation from target neutrality (0 = perfectly neutral) */
  delta_deviation_pct: number;
  /** Max acceptable deviation before rebalance */
  max_deviation_pct: number;
}

export interface PortfolioDeltaComposite {
  /** Aggregate across all strategies */
  total_delta_usd: number;
  total_delta_eth: number;
  total_delta_sol: number;
  total_delta_btc: number;
  /** Per-strategy breakdown */
  per_strategy: DeltaExposure[];
  /** Total liquidation cost as % of portfolio */
  total_liquidation_cost_pct: number;
}

// ---------------------------------------------------------------------------
// DeFi Reconciliation (on-chain vs system)
// ---------------------------------------------------------------------------

export interface DeFiReconciliationRecord {
  id: string;
  date: string;
  venue: DeFiVenue | string;
  instrument_id: string;
  break_type: "position" | "pnl" | "fee" | "gas" | "balance";
  /** What the chain/exchange reports */
  on_chain_value: number;
  /** What our system (position-balance-monitor) reports */
  system_value: number;
  /** Difference */
  delta: number;
  delta_pct: number;
  status: "pending" | "investigating" | "resolved" | "accepted";
  resolution?: "system_correct" | "chain_correct" | "adjusted";
}

// ---------------------------------------------------------------------------
// Rebalance
// ---------------------------------------------------------------------------

export interface RebalancePreview {
  treasury_current_pct: number;
  treasury_target_pct: number;
  treasury_balance_usd: number;
  total_aum_usd: number;
  action: "deploy" | "reduce"; // deploy = treasury high, reduce = treasury low
  /** Per-strategy proposed capital movement */
  allocations: RebalanceAllocation[];
  /** Total instructions that will be generated */
  total_instructions: number;
  estimated_gas_usd: number;
}

export interface RebalanceAllocation {
  strategy_id: DeFiStrategyId;
  current_balance_usd: number;
  proposed_change_usd: number; // positive = deploy more, negative = reduce
  instructions: StrategyInstruction[];
}

// ---------------------------------------------------------------------------
// Treasury
// ---------------------------------------------------------------------------

export interface TreasurySnapshot {
  timestamp: string;
  chain: string;
  custodian: string;
  treasury_balance_usd: number;
  total_trading_balance_usd: number;
  total_aum_usd: number;
  treasury_pct: number;
  status: "normal" | "low" | "high";
  per_strategy_balance: Record<DeFiStrategyId, number>;
  per_token_balance: Record<string, number>;
}

